  const ProgressiveBackground = ({ sdSrc, hdSrc, children, className = '', style = {}, ...props }) => {
    const [isVisible, setIsVisible] = useState(false);
    const [hdLoaded, setHdLoaded] = useState(false);
    const containerRef = useRef();

    // Lazy load trigger
    useEffect(() => {
      const observer = new IntersectionObserver(
        ([entry]) => {
          if (entry.isIntersecting) {
            setIsVisible(true);
            observer.disconnect();
          }
        },
        { rootMargin: '100px' }
      );

      if (containerRef.current) observer.observe(containerRef.current);
      return () => observer.disconnect();
    }, []);

    // Load HD background after SD if visible
    useEffect(() => {
      if (!isVisible) return;

      const hdImg = new Image();
      hdImg.src = hdSrc;
      hdImg.onload = () => {
        setHdLoaded(true);
      };
    }, [hdSrc, isVisible]);

    return (
      <div
        ref={containerRef}
        className={className}
        style={{
          ...style,
          backgroundImage: `url(${hdLoaded ? hdSrc : sdSrc})`,
          backgroundSize: 'cover',
          backgroundPosition: 'center',
          transition: 'background-image 0.5s ease-in-out, filter 0.4s ease',
          filter: hdLoaded ? 'blur(0)' : 'blur(1px)',
        }}
        {...props}
      >
        {children}
      </div>
    );
};

const Slideshow = React.memo(() => {
    const leftButtonRef = useRef();
    const rightButtonRef = useRef();
    const slideTimerRef = useRef(); // Store interval ID

    useEffect(() => {
        gsap.fromTo(
            leftButtonRef.current,
            { autoAlpha: 0, x: -50, opacity: 0 },
            {
                autoAlpha: 1,
                x: 0,
                opacity: 1,
                duration: 0.5,
                ease: "power2.out",
                scrollTrigger: {
                    scroller: ".hero-video-about-cont",
                    trigger: leftButtonRef.current,
                    start: "top 60%",
                    end: "bottom 0%",
                    toggleActions: "play none repeat reverse",
                },
            }
        );
        return () => {};
    }, []);

    useEffect(() => {
        gsap.fromTo(
            rightButtonRef.current,
            { autoAlpha: 0, x: 50, opacity: 0 },
            {
                autoAlpha: 1,
                x: 0,
                opacity: 1,
                duration: 0.5,
                ease: "power2.out",
                scrollTrigger: {
                    scroller: ".hero-video-about-cont",
                    trigger: rightButtonRef.current,
                    start: "top 60%",
                    end: "bottom 0%",
                    toggleActions: "play none repeat reverse",
                },
            }
        );
        return () => {};
    }, []);

    const sdSrc = useMemo(() => "/images/hero/sd_iitkgp-bg.avif", []);
    const hdSrc = useMemo(() => "/images/hero/hd_iitkgp-bg.avif", []);
    const [currentSlide, setCurrentSlide] = useState(0);

    useEffect(() => {
        slideTimerRef.current = setInterval(() => {
            setCurrentSlide((prev) => (prev + 1) % heroData.length);
        }, 15000);
        return () => clearInterval(slideTimerRef.current);
    }, []);

    const nextSlide = () => {
        clearInterval(slideTimerRef.current); // Clear the interval
        setCurrentSlide((prev) => (prev + 1) % heroData.length);
        // Restart the interval
        slideTimerRef.current = setInterval(() => {
            setCurrentSlide((prev) => (prev + 1) % heroData.length);
        }, 15000);
    };

    const prevSlide = () => {
        clearInterval(slideTimerRef.current); // Clear the interval
        setCurrentSlide((prev) => (prev - 1 + heroData.length) % heroData.length);
        // Restart the interval
        slideTimerRef.current = setInterval(() => {
            setCurrentSlide((prev) => (prev + 1) % heroData.length);
        }, 15000);
    };

    const heroChildren = heroData.map((data, index) => (
        <div
            key={index}
            className={`absolute inset-0 transition-opacity duration-1000 ${
                index === currentSlide ? "opacity-100" : "opacity-0"
            }`}
        >
            <div className="absolute inset-0 bg-gradient-to-br from-black via-gray-900/50 to-black/80"></div>
            <div
                className="flex flex-col md:flex-row w-full h-[80vh] md:h-[70vh] lg:h-[80vh] items-center justify-center px-4 sm:px-6 lg:px-8"
                style={{
                    WebkitUserSelect: "none",
                    msUserSelect: "none",
                    userSelect: "none",
                }}
            >
                <div className="flex flex-col items-center justify-center w-full md:w-1/3 mb-6 md:mb-0 relative top-16">
                    <div className="w-32 h-32 sm:w-40 sm:h-40 md:w-48 md:h-48 lg:w-52 lg:h-52 flex-shrink-0">
                        <picture>
                            <source srcSet={`${data.url}.avif`} type="image/avif" />
                            <source srcSet={`${data.url}.png`} type="image/png" />
                            <img src={`${data.url}.png`} alt={data.name} />
                        </picture>
                    </div>
                    <span
                        className="uppercase font-poppins font-bold mt-4 text-xl sm:text-2xl md:text-3xl lg:text-4xl text-center"
                        style={{
                            color: "#a6cb38",
                        }}
                    >
                        {data.name}
                    </span>
                    <span
                        className="mt-2 text-center text-sm sm:text-base md:text-lg font-serif"
                        style={{
                            color: "#acc730",
                            fontWeight: 530,
                        }}
                    >
                        {data.currentState}
                    </span>
                    <span
                        className="text-center text-sm sm:text-base md:text-lg font-serif text-white"
                        style={{
                            fontWeight: 530,
                        }}
                    >
                        {data.iitbackground}
                    </span>
                </div>
                <div className="relative flex flex-col items-center justify-center w-full md:w-2/3 text-center top-16">
                    <img
                        className="w-12 sm:w-16 md:w-20 aspect-square self-start"
                        src="/images/icons/open-quote.svg"
                    />
                    <div className="px-4 sm:px-6 md:px-8 lg:px-12">
                        <span className="text-white font-serif text-xl sm:text-2xl md:text-3xl lg:text-4xl">
                            {data.testimonial}
                        </span>
                    </div>
                    <img
                        className="w-12 sm:w-16 md:w-20 aspect-square self-end"
                        src="/images/icons/close-quote.svg"
                    />
                </div>
            </div>
        </div>
    ));

    return (
        <>
            <ProgressiveBackground
                className="absolute inset-0 z-0 w-full h-full"
                sdSrc={sdSrc}
                hdSrc={hdSrc}
            >
                {heroChildren}
            </ProgressiveBackground>

            <div ref={leftButtonRef} className="absolute top-1/2 left-4 z-20 transform -translate-y-1/2">
                <button
                    onClick={prevSlide}
                    className="bg-white/20 backdrop-blur-sm text-white p-2 sm:p-3 rounded-full hover:bg-white/30 transition-all duration-300 shadow-lg border border-white/30"
                >
                    <ChevronLeft className="w-5 h-5 sm:w-6 sm:h-6" />
                </button>
            </div>
            <div ref={rightButtonRef} className="absolute top-1/2 right-4 z-20 transform -translate-y-1/2">
                <button
                    onClick={nextSlide}
                    className="bg-white/20 backdrop-blur-sm text-white p-2 sm:p-3 rounded-full hover:bg-white/30 transition-all duration-300 shadow-lg border border-white/30"
                >
                    <ChevronRight className="w-5 h-5 sm:w-6 sm:h-6" />
                </button>
            </div>

            <div className="absolute bottom-10 left-1/2 transform -translate-x-1/2 z-20 flex space-x-2">
                {heroData.map((_, index) => (
                    <button
                        key={index}
                        onClick={() => {
                            clearInterval(slideTimerRef.current); // Clear interval on dot click
                            setCurrentSlide(index);
                            // Restart the interval
                            slideTimerRef.current = setInterval(() => {
                                setCurrentSlide((prev) => (prev + 1) % heroData.length);
                            }, 15000);
                        }}
                        className={`w-2 h-2 sm:w-3 sm:h-3 rounded-full transition-all duration-300 ${
                            index === currentSlide ? "bg-white" : "bg-white/50"
                        }`}
                    />
                ))}
            </div>
        </>
    );
});

