const Counter = ({ start, end, label, isVisible, duration = 2000 }) => {
  const countRef = useRef(start);
  const displayRef = useRef(null);

  useEffect(() => {
    if (!isVisible) return;

    const increment = (end - start) / (duration / 16);
    let current = start;
    const timer = setInterval(() => {
      current += increment;
      if (current >= end) {
        countRef.current = end;
        displayRef.current.textContent = `${end}+`;
        clearInterval(timer);
      } else {
        countRef.current = Math.floor(current);
        displayRef.current.textContent = `${countRef.current}+`;
      }
    }, 16);

    return () => clearInterval(timer);
  }, [isVisible, start, end, duration]);

  return (
    <div className="text-center">
      <div
        ref={displayRef}
        className="text-5xl md:text-6xl font-bold mb-2 text-[#fed23d]"
      >
        {start}+
      </div>
      <div className="text-xl opacity-90 text-gray-300">{label}</div>
    </div>
  );
};

