import React from "react";
import { FaWhatsapp } from "react-icons/fa";

const WhatsAppFloatingButton = () => {
  const phoneNumber = "918227922352"; // Replace with your WhatsApp number

  const openWhatsApp = () => {
    window.open(`https://wa.me/${phoneNumber}`, "_blank");
  };

  return (
    <div className="fixed bottom-6 right-6 z-50">
      <div className="relative group">
        {/* Ripple Animation */}
        <span className="absolute inset-0 rounded-full bg-green-400 opacity-75 animate-ping z-0"></span>

        {/* WhatsApp Button */}
        <button
          onClick={openWhatsApp}
          className="relative z-10 bg-green-500 hover:bg-green-600 text-white p-4 rounded-full shadow-lg flex items-center justify-center transition-transform duration-300 active:scale-90"
          aria-label="Chat on WhatsApp"
        >
          <FaWhatsapp size={24} />
        </button>

        {/* Tooltip (hidden on small screens) */}
        <div className="absolute right-16 top-1/2 transform -translate-y-1/2 bg-gray-800 text-white text-xs px-3 py-1 rounded opacity-0 group-hover:opacity-100 transition-opacity duration-200 hidden sm:block">
          Chat on WhatsApp
        </div>
      </div>
    </div>
  );
};

export default WhatsAppFloatingButton;
